sql:
SELECT COUNT(doc_id) AS draft_count
FROM document_status
WHERE status = 'draft';

SELECT doc_id, status
FROM document_status
WHERE status = 'draft';

SELECT doc_type_name
FROM document_types
WHERE template_id > 0;

SELECT COUNT(doc_id) AS current_version_count
FROM document_versions
WHERE is_current = 1;

SELECT DISTINCT doc_id 
FROM access_logs 
ORDER BY doc_id;

